import { initLiquidGlass } from "./liquid-glass.js";

const $ = id => document.getElementById(id);
const STEPS = ["stage", "roles", "cities", "keywords"];
const STAGE_LABELS = {"校招": "校园招聘", "校园招聘": "校园招聘", "实习": "日常实习", "日常实习": "日常实习"};
const COMMON_CITIES = ["北京", "上海", "深圳", "广州", "杭州", "南京", "成都", "武汉"];
const REDUCE_MOTION = matchMedia("(prefers-reduced-motion: reduce)");
const state = {options:null,preferences:null,originalProfile:null,draft:null,builderMode:"first",activeStep:"stage",activeRoleTab:0,activeProvince:"",completedSteps:new Set(),jobs:[],recommendedJobs:[],jobTotal:0,recommendedTotal:0,expiringTotal:0,todayRecommendedTotal:0,radarCurrentTotal:0,page:1,pages:0,pageSize:12,radarPage:1,radarPages:0,radarPageSize:8,recommendationScope:"today",facets:{cities:[],batches:[],company_types:[],directions:[]},activeTask:null,scanStatus:{state:"never"},lastScan:null,rematching:false,drawerJob:null,drawerTrigger:null,modalClosing:false,lastTaskActivity:"",jobSequence:0,jobLookup:new Map()};
let notificationTimer;

function detailText(detail){if(Array.isArray(detail))return detail.join("；");if(detail&&typeof detail==="object")return detail.message||"操作未完成";return String(detail||"请求失败")}
async function api(url,options){const response=await fetch(url,options);const data=await response.json().catch(()=>({}));if(!response.ok){const error=new Error(detailText(data.detail||data));error.detail=data.detail;throw error}return data}
function escapeHtml(value){return String(value??"").replace(/[&<>'"]/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[char]))}
function unique(values=[]){return [...new Set(values.map(value=>String(value).trim()).filter(Boolean))]}
function profileCopy(profile={},first=false){return{batches:first?[]:unique(profile.batches),role_groups:first?[]:unique(profile.role_groups),target_cities:first?[]:unique(profile.target_cities),custom_keywords:first?[]:unique(profile.custom_keywords),selected_company_groups:first?[]:unique(profile.selected_company_groups),custom_companies:first?[]:unique(profile.custom_companies),exclude_role_groups:first?[]:unique(profile.exclude_role_groups),cityMode:first?null:(profile.target_cities?.length?"selected":"any")}}
function stageLabel(value){return STAGE_LABELS[value]||value}
function stageKind(profile=state.draft){return unique(profile?.batches||[]).map(stageLabel).join(" + ")}
function setLoading(button,loading,label){if(!button)return;button.disabled=loading;button.classList.toggle("loading",loading);if(label){if(loading){button.dataset.label=button.textContent;button.textContent=label}else if(button.dataset.label){button.textContent=button.dataset.label;delete button.dataset.label}}}
function toast(message){const node=document.createElement("div");node.className="toast";node.textContent=message;$('toast-region').append(node);setTimeout(()=>node.remove(),2800)}
function hideHomeNotification(){clearTimeout(notificationTimer);const root=$("home-notification");root.classList.remove("visible");setTimeout(()=>{if(!root.classList.contains("visible"))root.replaceChildren()},220)}
function showHomeNotification(title,text,{kind="",duration=5000,retry=false}={}){clearTimeout(notificationTimer);const root=$("home-notification");root.className=`home-notification ${kind}`;root.innerHTML=`<div><strong>${escapeHtml(title)}</strong><span>${escapeHtml(text)}</span></div>${retry?'<button class="button secondary" data-action="rematch" type="button">重新匹配</button>':`<button class="icon-button" data-action="close-notification" type="button" aria-label="关闭通知">${icon("close")}</button>`}`;requestAnimationFrame(()=>root.classList.add("visible"));if(duration)notificationTimer=setTimeout(hideHomeNotification,duration)}
function icon(name){return `<svg aria-hidden="true"><use href="#i-${name}"/></svg>`}
function taskCurveLoader(){const path="M40.0,25.0 L39.2,25.9 L37.0,26.5 L33.7,26.7 L29.5,26.2 L25.0,25.0 L20.7,23.3 L17.0,21.2 L14.4,19.2 L13.0,17.4 L12.9,16.2 L14.0,15.9 L16.2,16.7 L19.0,18.6 L22.0,21.4 L25.0,25.0 L27.5,28.9 L29.2,32.7 L30.2,36.0 L30.3,38.3 L29.6,39.3 L28.5,38.8 L27.3,36.9 L26.1,33.7 L25.3,29.6 L25.0,25.0 L25.3,20.4 L26.1,16.3 L27.3,13.1 L28.5,11.2 L29.6,10.7 L30.3,11.7 L30.2,14.0 L29.2,17.3 L27.5,21.1 L25.0,25.0 L22.0,28.6 L19.0,31.4 L16.2,33.3 L14.0,34.1 L12.9,33.8 L13.0,32.6 L14.4,30.8 L17.0,28.8 L20.7,26.7 L25.0,25.0 L29.5,23.8 L33.7,23.3 L37.0,23.5 L39.2,24.1 L40.0,25.0 Z";if(REDUCE_MOTION.matches)return `<svg class="task-curve-loader" viewBox="0 0 50 50" aria-hidden="true"><g class="task-curve-static"><circle cx="17" cy="20" r="1.8"/><circle cx="24" cy="14" r="1.4"/><circle cx="31" cy="19" r="1.7"/><circle cx="21" cy="28" r="1.5"/><circle cx="29" cy="27" r="2"/><circle cx="35" cy="34" r="1.3"/><circle cx="16" cy="35" r="1.2"/></g></svg>`;const particles=Array.from({length:19},(_,index)=>`<circle r="${(1.9-index*.035).toFixed(2)}" opacity="${(.98-index*.035).toFixed(2)}"><animateMotion dur="${(3.1+(index%4)*.18).toFixed(2)}s" begin="-${(index*.17).toFixed(2)}s" repeatCount="indefinite"><mpath href="#task-curve-path"/></animateMotion></circle>`).join("");return `<svg class="task-curve-loader" viewBox="0 0 50 50" aria-hidden="true"><path id="task-curve-path" class="task-curve-track" d="${path}"/><g class="task-curve-particles">${particles}</g></svg>`}

function mountBuilder(mode){state.builderMode=mode;state.originalProfile=profileCopy(state.preferences.user_profile);state.draft=profileCopy(state.preferences.user_profile,mode==="first");state.activeStep=mode==="first"?"stage":null;state.activeRoleTab=0;state.activeProvince="";state.completedSteps=new Set(mode==="first"?[]:STEPS);const host=mode==="first"?$("onboarding-builder-host"):$("preferences-builder-host");const other=mode==="first"?$("preferences-builder-host"):$("onboarding-builder-host");const existing=$("radar-builder");if(existing)host.append(existing);else host.append($("radar-builder-template").content.cloneNode(true));other?.classList.add("hidden");host.classList.remove("hidden");bindBuilder();renderBuilder()}

function bindBuilder(){const form=$("builder-form");if(form.dataset.bound)return;form.dataset.bound="true";form.addEventListener("submit",event=>{event.preventDefault();saveBuilder()});form.addEventListener("click",event=>{const edit=event.target.closest(".step-edit");if(edit){state.activeStep=edit.closest("[data-builder-step]").dataset.builderStep;renderBuilder();return}const choice=event.target.closest("[data-choice]");if(choice){toggleChoice(choice);return}const tab=event.target.closest("[data-role-tab]");if(tab){state.activeRoleTab=Number(tab.dataset.roleTab);renderRoleTabs();renderRoleOptions();return}const next=event.target.closest(".step-continue");if(next){completeCurrentStep(next.closest("[data-builder-step]").dataset.builderStep)}});$("builder-role-search").addEventListener("input",renderRoleOptions);$("builder-city-search").addEventListener("input",renderCityOptions);$("builder-province-select").addEventListener("change",event=>{state.activeProvince=event.target.value;renderCityOptions()});$("add-builder-keyword").onclick=addKeywords;$("builder-keyword").addEventListener("keydown",event=>{if(event.key==="Enter"){event.preventDefault();addKeywords()}});$("builder-keyword").addEventListener("input",event=>{if(/[，,]/.test(event.target.value))addKeywords()});$("add-builder-company").onclick=addCompanies;$("builder-company").addEventListener("keydown",event=>{if(event.key==="Enter"){event.preventDefault();addCompanies()}});$("cancel-builder").onclick=closePreferenceBuilder}

function renderBuilder(){renderStepState();renderBatchOptions();renderRoleTabs();renderRoleOptions();renderCityOptions();renderKeywords();renderOrganizationOptions();renderCompanies();renderExcludedOptions();renderRadarPreview();const first=state.builderMode==="first",ready=STEPS.every(step=>stepComplete(step)),save=$("save-builder"),actions=save.closest(".builder-actions"),keywordButton=document.querySelector('[data-builder-step="keywords"] .step-continue'),hasSignals=state.draft.custom_keywords.length||state.draft.selected_company_groups.length||state.draft.custom_companies.length;$("cancel-builder").classList.toggle("hidden",first);actions.classList.toggle("hidden",first&&!ready);actions.classList.toggle("onboarding-ready",first&&ready);save.textContent=first?"创建岗位雷达并开始扫描":"保存并重新匹配岗位";if(keywordButton)keywordButton.textContent=hasSignals?"完成配置":"暂不添加，完成配置"}

function stepComplete(step){const confirmed=state.completedSteps.has(step);if(step==="stage")return confirmed&&Boolean(state.draft.batches.length);if(step==="roles")return confirmed&&Boolean(state.draft.role_groups.length);if(step==="cities")return confirmed&&state.draft.cityMode!==null;return confirmed}
function stepSummary(step){if(step==="stage")return stageKind()||"尚未选择";if(step==="roles")return state.draft.role_groups.length?state.draft.role_groups.map(displayRole).join(" · "):"尚未选择";if(step==="cities")return state.draft.cityMode==="any"?"不限城市":state.draft.target_cities.length?state.draft.target_cities.map(displayLocation).join(" · "):"尚未选择";const signals=[...state.draft.selected_company_groups.map(displayOrganization),...state.draft.custom_companies,...state.draft.custom_keywords];return signals.length?signals.join(" · "):state.builderMode==="first"&&state.completedSteps.has("keywords")?"已跳过":"未添加补充信号"}
function renderStepState(){document.querySelectorAll("[data-builder-step]").forEach((section,index)=>{const step=section.dataset.builderStep;const open=state.activeStep===step;const done=stepComplete(step);section.classList.toggle("active",open);section.classList.toggle("complete",done&&!open);section.querySelector(".step-body").classList.toggle("hidden",!open);section.querySelector(".step-summary").textContent=open?"":stepSummary(step);section.querySelector(".step-edit").classList.toggle("hidden",open||(!done&&state.builderMode==="first"));section.querySelector(".step-index").innerHTML=done&&!open?icon("check"):String(index+1)})}
function completeCurrentStep(step){if((step==="roles"&&!state.draft.role_groups.length)||(step==="stage"&&!state.draft.batches.length)||(step==="cities"&&state.draft.cityMode===null)){showBuilderError(step==="roles"?"请至少选择一个关注方向。":step==="cities"?"请选择期望城市或不限城市。":"请选择求职阶段。");return}state.completedSteps.add(step);const next=STEPS[STEPS.indexOf(step)+1];state.activeStep=next||null;showBuilderError("");renderBuilder();if(next)requestAnimationFrame(()=>document.querySelector(`[data-builder-step="${next}"]`)?.scrollIntoView({behavior:matchMedia("(prefers-reduced-motion: reduce)").matches?"auto":"smooth",block:"center"}))}
function showBuilderError(message){$("builder-error").textContent=message;$("builder-error").classList.toggle("hidden",!message)}

function renderBatchOptions(){const items=(state.options?.batches||[]).filter(item=>["校招","实习","校园招聘","日常实习"].includes(item.value));$("builder-batches").innerHTML=items.map(item=>{const label=stageLabel(item.value);const campus=label==="校园招聘";return `<button class="stage-card" type="button" data-choice="batch" data-value="${escapeHtml(item.value)}" aria-pressed="${state.draft.batches.includes(item.value)}"><strong>${label}</strong><span>${campus?"面向应届生的提前批、秋招、春招及补录岗位":"面向在校生的长期或短期实习岗位"}</span></button>`}).join("")}
function renderRoleTabs(){const sections=state.options?.role_sections||[];$("role-tabs").innerHTML=sections.map((section,index)=>`<button type="button" role="tab" data-role-tab="${index}" aria-selected="${state.activeRoleTab===index}">${escapeHtml(section.label)}</button>`).join("")}
function renderRoleOptions(){const sections=state.options?.role_sections||[];const query=$("builder-role-search")?.value.trim().toLowerCase()||"";let items;if(query)items=sections.flatMap(section=>section.options||[]).filter(item=>[item.label,item.value,...(item.search_terms||[])].join(" ").toLowerCase().includes(query));else items=sections[state.activeRoleTab]?.options||[];$("builder-roles").innerHTML=items.map(item=>choiceButton("role",item.value,item.label,state.draft.role_groups.includes(item.value))).join("");$("role-selection-count").textContent=`已选择 ${state.draft.role_groups.length} 个方向`;renderChips($("selected-roles"),state.draft.role_groups,"role");$("role-guidance").textContent=state.draft.role_groups.length>5?"当前关注方向较多，后续可能看到更多岗位。":"建议选择 1-5 个核心方向；搜索会同时查找系统联想词。"}
function locationSections(){return state.options?.location_sections||[]}
function allLocations(){return locationSections().flatMap(section=>[section,...(section.cities||[])])}
function cityItems(){const query=$("builder-city-search")?.value.trim().toLowerCase()||"";if(query)return allLocations().filter(item=>`${item.label} ${item.value}`.toLowerCase().includes(query)).slice(0,30);const active=locationSections().find(item=>item.value===state.activeProvince);if(active)return[active,...(active.cities||[])];const cities=locationSections().flatMap(item=>item.cities||[]);return COMMON_CITIES.map(name=>cities.find(item=>item.label.includes(name))).filter(Boolean)}
function renderCityOptions(){const provinces=locationSections(),select=$("builder-province-select");select.innerHTML='<option value="">选择省份</option>'+provinces.map(item=>`<option value="${escapeHtml(item.value)}">${escapeHtml(item.label)}</option>`).join("");select.value=state.activeProvince;$("builder-cities").innerHTML=choiceButton("city-any","","不限城市",state.draft.cityMode==="any")+cityItems().map(item=>choiceButton("city",item.value,item.label,state.draft.target_cities.includes(item.value))).join("");renderChips($("selected-cities"),state.draft.target_cities,"city")}
function choiceButton(type,value,label,selected){return `<button class="choice-button" type="button" data-choice="${type}" data-value="${escapeHtml(value)}" aria-pressed="${selected}">${escapeHtml(label)}</button>`}
function displayLocation(value){return allLocations().find(item=>item.value===value)?.label||value}
function displayOrganization(value){return (state.options?.organization_groups||[]).find(item=>item.value===value)?.label||value}
function displayValue(value,type){if(type==="role")return displayRole(value);if(type==="city")return displayLocation(value);if(type==="organization")return displayOrganization(value);return value}
function renderChips(root,items,type){root.innerHTML=items.map(value=>{const label=displayValue(value,type);return `<span class="selected-item">${escapeHtml(label)}<button type="button" data-choice="remove-${type}" data-value="${escapeHtml(value)}" aria-label="删除 ${escapeHtml(label)}">${icon("close")}</button></span>`}).join("")}

function toggleChoice(button){const type=button.dataset.choice,value=button.dataset.value;if(type==="batch")toggleList(state.draft.batches,value);else if(type==="role")toggleList(state.draft.role_groups,value);else if(type==="remove-role")state.draft.role_groups=state.draft.role_groups.filter(item=>item!==value);else if(type==="city-any"){state.draft.cityMode="any";state.draft.target_cities=[]}else if(type==="city"){state.draft.cityMode="selected";toggleList(state.draft.target_cities,value);if(!state.draft.target_cities.length)state.draft.cityMode=null}else if(type==="remove-city"){state.draft.target_cities=state.draft.target_cities.filter(item=>item!==value);if(!state.draft.target_cities.length)state.draft.cityMode=null}else if(type==="organization")toggleList(state.draft.selected_company_groups,value);else if(type==="remove-organization")state.draft.selected_company_groups=state.draft.selected_company_groups.filter(item=>item!==value);else if(type==="remove-company")state.draft.custom_companies=state.draft.custom_companies.filter(item=>item!==value);else if(type==="remove-keyword")state.draft.custom_keywords=state.draft.custom_keywords.filter(item=>item!==value);else if(type==="excluded")toggleList(state.draft.exclude_role_groups,value);showBuilderError("");renderBuilder()}
function toggleList(list,value){const index=list.indexOf(value);if(index>=0)list.splice(index,1);else list.push(value)}
function addKeywords(){const input=$("builder-keyword");const additions=input.value.split(/[,，\n]+/).map(word=>word.trim().replace(/\s+/g," ")).filter(Boolean);state.draft.custom_keywords=unique([...state.draft.custom_keywords,...additions]).slice(0,12);input.value="";renderKeywords();renderRadarPreview()}
function renderKeywords(){renderChips($("builder-keywords"),state.draft.custom_keywords,"keyword");$("keyword-guidance").textContent=state.draft.custom_keywords.length>=8?"关键词已较丰富，建议只保留真正重要的信号。":"支持回车、中文或英文逗号分隔，最多 12 个。"}
function addCompanies(){const input=$("builder-company"),additions=input.value.split(/[,，\n]+/).map(word=>word.trim().replace(/\s+/g," ")).filter(Boolean);state.draft.custom_companies=unique([...state.draft.custom_companies,...additions]).slice(0,12);input.value="";renderCompanies();renderRadarPreview()}
function renderCompanies(){renderChips($("builder-companies"),state.draft.custom_companies,"company")}
function renderOrganizationOptions(){const items=state.options?.organization_groups||[];$("builder-organization-groups").innerHTML=items.map(item=>choiceButton("organization",item.value,item.label,state.draft.selected_company_groups.includes(item.value))).join("")}
function renderExcludedOptions(){const items=(state.options?.exclude_role_sections||state.options?.role_sections||[]).flatMap(section=>section.options||[]);$("builder-excluded-roles").innerHTML=items.map(item=>choiceButton("excluded",item.value,item.label,state.draft.exclude_role_groups.includes(item.value))).join("")}

function focusScore(profile=state.draft){const roles=profile.role_groups?.length||0,cities=profile.target_cities?.length||0,keywords=(profile.custom_keywords?.length||0)+(profile.selected_company_groups?.length||0)+(profile.custom_companies?.length||0),excluded=profile.exclude_role_groups?.length||0;const stage=profile.batches?.length?20:0,roleScore=roles?Math.min(35,20+(roles-1)*5):0,cityScore=profile.cityMode==="any"?8:cities?Math.min(25,16+(cities-1)*3):0,keywordScore=Math.min(12,keywords*3),excludedScore=Math.min(8,excluded*4),score=Math.min(100,stage+roleScore+cityScore+keywordScore+excludedScore);if(score<25)return{label:"待完善",rank:0,score};if(score<50)return{label:"初步聚焦",rank:1,score};if(score<70)return{label:"已聚焦",rank:2,score};if(score<85)return{label:"偏好清晰",rank:3,score};return{label:"高度聚焦",rank:4,score}}
function canonicalProfile(profile={}){return{batches:unique(profile.batches).sort(),role_groups:unique(profile.role_groups).sort(),target_cities:unique(profile.target_cities).sort(),custom_keywords:unique(profile.custom_keywords).sort(),selected_company_groups:unique(profile.selected_company_groups).sort(),custom_companies:unique(profile.custom_companies).sort(),exclude_role_groups:unique(profile.exclude_role_groups).sort(),cityMode:profile.cityMode??null}}
function profileChanged(){return state.builderMode==="edit"&&JSON.stringify(canonicalProfile(state.originalProfile))!==JSON.stringify(canonicalProfile(state.draft))}
function displayRole(value){for(const section of state.options?.role_sections||[]){const match=(section.options||[]).find(item=>item.value===value);if(match)return match.label}return value}
function radarLine(profile){const stage=stageKind(profile),role=displayRole(profile.role_groups?.[0]||""),city=profile.cityMode==="any"?"全国":displayLocation(profile.target_cities?.[0]||"");return [stage,role,city].filter(Boolean).join(" · ")||"从中心开始建立关注范围"}
function previewStatus(){if(state.builderMode==="first")return{label:"构建中",kind:"building"};if(profileChanged())return{label:"调整中",kind:"adjusting"};return{label:"已就绪",kind:"ready"}}
function limitedNodes(items,type,limit){const shown=items.slice(0,limit).map(value=>({text:type==="role"?displayRole(value):value,full:value}));if(items.length>limit)shown.push({text:`+${items.length-limit}`,full:`另有 ${items.length-limit} 项`});return shown.map((item,index)=>({...item,type,index,total:shown.length,key:`${type}:${item.full}`}))}
function orbitNodes(profile){const cities=profile.cityMode==="any"?["不限城市"]:(profile.target_cities||[]).map(displayLocation),signals=[...(profile.selected_company_groups||[]).map(displayOrganization),...(profile.custom_companies||[]),...(profile.custom_keywords||[])];return[...limitedNodes(profile.role_groups||[],"role",4),...limitedNodes(cities,"city",4),...limitedNodes(signals,"keyword",3)]}
function syncOrbitLayer(layer,nodes){const wanted=new Map(nodes.map(node=>[node.key,node]));layer.querySelectorAll(".orbit-node").forEach(element=>{if(wanted.has(element.dataset.key))return;element.classList.add("leaving");clearTimeout(element._removeTimer);element._removeTimer=setTimeout(()=>element.remove(),180)});nodes.forEach(node=>{let element=layer.querySelector(`[data-key="${CSS.escape(node.key)}"]`);if(!element){element=document.createElement("div");element.className="orbit-node entering";element.dataset.key=node.key;element.innerHTML='<span class="orbit-node-chip"><span class="orbit-node-text"></span></span>';layer.append(element);requestAnimationFrame(()=>element.classList.remove("entering"))}clearTimeout(element._removeTimer);element.classList.remove("leaving");element.style.setProperty("--angle",`${(node.index/(node.total||1))*360+(node.type==="city"?22:node.type==="keyword"?8:-12)}deg`);const chip=element.querySelector(".orbit-node-chip"),text=element.querySelector(".orbit-node-text");chip.title=node.full;text.textContent=node.text})}
function renderOrbitRadar(root,profile,activeStep=""){if(!root.firstElementChild)root.innerHTML='<figure class="orbit-radar"><svg viewBox="0 0 320 320" aria-hidden="true"><circle class="coverage-field" cx="160" cy="160" r="145"/><circle class="orbit-track keyword" cx="160" cy="160" r="144"/><circle class="orbit-track city" cx="160" cy="160" r="112"/><circle class="orbit-track role" cx="160" cy="160" r="78"/></svg><div class="orbit-layer role" data-layer="role"></div><div class="orbit-layer city" data-layer="city"></div><div class="orbit-layer keyword" data-layer="keyword"></div><div class="radar-center"><strong></strong></div><figcaption class="sr-only"></figcaption></figure>';const visual=root.querySelector(".orbit-radar"),stage=stageKind(profile),centerStage=stage.replace("校园招聘","校招").replace("日常实习","实习").replace(" + ","·"),focus=focusScore(profile),nodes=orbitNodes(profile),active=activeStep==="roles"?"role":activeStep==="cities"?"city":activeStep==="keywords"?"keyword":activeStep;visual.dataset.activeLayer=active||"";visual.classList.toggle("is-editing",Boolean(activeStep));visual.style.setProperty("--focus-scale",String(stage?Math.max(.38,.48+focus.score*.0046):.28));visual.classList.toggle("has-stage",Boolean(stage));visual.classList.toggle("has-multiple-stages",(profile.batches||[]).length>1);const formed={role:Boolean(profile.role_groups.length),city:profile.cityMode!==null,keyword:Boolean(profile.custom_keywords.length)};["role","city","keyword"].forEach(type=>{visual.querySelector(`.orbit-track.${type}`).classList.toggle("formed",formed[type]);visual.querySelector(`.orbit-track.${type}`).classList.toggle("active",active===type);syncOrbitLayer(visual.querySelector(`.orbit-layer.${type}`),nodes.filter(node=>node.type===type))});visual.querySelector(".radar-center").classList.toggle("active",active==="stage");visual.querySelector(".radar-center strong").textContent=centerStage||"待选择";visual.querySelector("figcaption").textContent=`${radarLine(profile)}，偏好聚焦度 ${focus.score}%`}
